109→export function grantRandomPowerUp(game) {
110→    const powerUpTypes = game.selectedPowerUps;
111→    let powerUpType = null;
112→
113→    if (game.deterministicPowerUpCycleEnabled) {
114→        const index = game.powerUpCycleIndex % powerUpTypes.length;
115→        powerUpType = powerUpTypes[index];
116→        game.powerUpCycleIndex = (index + 1) % powerUpTypes.length;
117→    } else {
118→        powerUpType = powerUpTypes[Math.floor(Math.random() * powerUpTypes.length)];
119→    }
120→
121→    grantPowerUp(game, powerUpType);
122→    showPowerUpRewardAnimation(game, powerUpType);
123→}
