246→export function createMergedTiles(game, group, wasUserSwap = false) {
247→    const formationType = getFormationConfig(group.direction);
248→    let specialTileType = formationType ? game.specialTileConfig[formationType] : null;
249→
250→    // When Super Streak is active and the setting is enabled,
251→    // replace Wildcard (joker) rewards with Wildcard Teleport
