253→        specialTileType = "wild_teleport";
254→    }
255→
256→    // Calculate positions and value based on formation type
257→    const isTLFormation = group.direction === "T-formation" || group.direction === "L-formation";
258→    const is5LineFormation = group.direction === "line_5_horizontal" || group.direction === "line_5_vertical";
259→    const positions = isTLFormation ? [group.intersection] : calculateMiddlePositions(game, group.tiles, group);
260→    const valueIncrement = isTLFormation || is5LineFormation ? 2 : 1;
261→
262→    const newValue = group.value + valueIncrement;
263→
264→    // Check if sticky free swap should transfer (detected before tiles were cleared)
265→    // If so, and this was NOT a user swap, transfer the sticky free swap to the merged tile
266→    const hasStickyFreeSwap = group.hasStickyFreeSwap || false;
267→    const transferStickyFreeSwap = hasStickyFreeSwap && !wasUserSwap;
268→
269→    // Track intermediate values for formations that skip a level (T, L, 5-line)
270→    // When tiles of value N merge into 1 tile of value N+2, conceptually there's an intermediate step:
271→    // - T/L formation (5 tiles): 5 tiles → 3 tiles of N+1 → 1 tile of N+2
272→    // - 5-line formation (5 tiles): 5 tiles → 3 tiles of N+1 → 1 tile of N+2
273→    // So we track 3 creations of the intermediate value (N+1)
274→    if (isTLFormation || is5LineFormation) {
275→        const intermediateValue = group.value + 1;
276→        trackGoalProgress(game, intermediateValue, 3);
277→    }
278→
279→    // Handle special tile types
280→    if (specialTileType === "joker" || specialTileType === "wild_teleport") {
281→        // Joker and wild_teleport are special - they create JOKER type tiles, not normal tiles with properties
282→        const createSpecialTile = specialTileType === "wild_teleport" ? createWildTeleportTile : createJokerTile;
283→
284→        if (positions.length > 1) {
285→            const formationKey = group.direction.includes("block") ? "block_4" : "line_4";
286→            const specialPos = determineSpecialTilePosition(game, group, formationKey);
287→            const normalPos = positions.find((p) => p.row !== specialPos.row || p.col !== specialPos.col);
288→
289→            game.board[specialPos.row][specialPos.col] = createSpecialTile();
290→            game.board[normalPos.row][normalPos.col] = createTile(newValue, null, { transferStickyFreeSwap });
291→            trackGoalProgress(game, newValue, 1);
292→        } else {
293→            game.board[positions[0].row][positions[0].col] = createSpecialTile();
294→        }

