136→export function consumePowerUp(game, type) {
137→    game.powerUpUsedCounts[type]++;
138→
139→    const counts = game.powerUpCounts[type];
140→    if (counts.transient > 0) {
141→        counts.transient--;
142→    } else if (game.persistentPowerUpsEnabled && counts.persistent > 0) {
143→        counts.persistent--;
144→        savePowerUpCounts({
145→            hammer: game.powerUpCounts.hammer.persistent,
