                track("extra_moves_used", {
                    level: this.currentLevel,
                    extra_moves_count: 5,
                    included_swap: true,
                    moves_used: this.movesUsed,
                });

                // Mark that extra moves have been used for this level
                this.extraMovesUsed = true;

                this.maxMoves += 5;
