        const cbs = document.querySelectorAll(".powerup-select-cb");
        const checkedCount = Array.from(cbs).filter((cb) => cb.checked).length;
        cbs.forEach((cb) => {
            if (!cb.checked) {
                cb.disabled = checkedCount >= 3;
            }
        });
    };

