            if (e.target === settingsDialog) {
                settingsDialog.classList.add("hidden");
            }
        });

        document.addEventListener("keydown", (e) => {
            if (e.key === "Escape" && !settingsDialog.classList.contains("hidden")) {
                settingsDialog.classList.add("hidden");
            }
        });
    }
}

